const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const uuidv4 = require('uuid/v4');

const app = express();
const server = http.createServer(app);
const io = socketIo(server);

let players = {};

io.on('connection', (socket) => {
  console.log('A user connected:', socket.id);

  // Player authentication and session management
  socket.emit('requestAuth');
  socket.on('authResponse', (username) => {
    if (!players[username]) {
      players[username] = { id: uuidv4(), score: 0 };
    }
    socket.username = username;
    socket.id = players[username].id;
    console.log(`Player authenticated: ${username}, ID: ${socket.id}`);
  });

  // Accept username and score from client
  socket.on('updateScore', (score) => {
    if (players[socket.username]) {
      players[socket.username].score += score;
      io.emit('leaderboardUpdate', players);
    }
  });

  // Validate player moves on client side
  socket.on('validateMove', (move) => {
    // Implement move validation logic here
    // Example: check if the move is within bounds, valid action, etc.
    const isValid = true; // Replace with actual validation logic
    io.emit('moveValidationResult', { username: socket.username, isValid });
  });

  // Handle disconnection
  socket.on('disconnect', () => {
    console.log('User disconnected:', socket.id);
    if (socket.username) {
      delete players[socket.username];
    }
  });
});

server.listen(3000, () => {
  console.log('Server is running on port 3000');
});